class AppCoordinator {
    
    func start(window: UIWindow) {
        let rootViewController: UIViewController
        
        if BiometricAuthManager.shared.isAuthenticated && BiometricAuthManager.shared.isBiometricEnabled {
            rootViewController = SplashViewController()
        } else {
            rootViewController = LoginViewController()
        }
        
        window.rootViewController = rootViewController
        window.makeKeyAndVisible()
    }
}

class SplashViewController: UIViewController {
    
    private let activityIndicator: UIActivityIndicatorView = {
        let indicator = UIActivityIndicatorView(style: .large)
        indicator.translatesAutoresizingMaskIntoConstraints = false
        return indicator
    }()
    
    private let titleLabel: UILabel = {
        let label = UILabel()
        label.text = "Authenticating..."
        label.font = UIFont.systemFont(ofSize: 24, weight: .semibold)
        label.textAlignment = .center
        label.translatesAutoresizingMaskIntoConstraints = false
        return label
    }()
    
    override func viewDidLoad() {
        super.viewDidLoad()
        setupUI()
    }
    
    override func viewDidAppear(_ animated: Bool) {
        super.viewDidAppear(animated)
        attemptBiometricAuthentication()
    }
    
    private func setupUI() {
        view.backgroundColor = .systemBackground
        
        view.addSubview(titleLabel)
        view.addSubview(activityIndicator)
        
        NSLayoutConstraint.activate([
            titleLabel.centerXAnchor.constraint(equalTo: view.centerXAnchor),
            titleLabel.centerYAnchor.constraint(equalTo: view.centerYAnchor),
            
            activityIndicator.centerXAnchor.constraint(equalTo: view.centerXAnchor),
            activityIndicator.topAnchor.constraint(equalTo: titleLabel.bottomAnchor, constant: 20)
        ])
        
        activityIndicator.startAnimating()
    }
    
    private func attemptBiometricAuthentication() {
        BiometricAuthManager.shared.authenticateWithBiometrics { [weak self] success, error in
            if success {
                self?.navigateToHome()
            } else {
                self?.navigateToLogin()
            }
        }
    }
    
    private func navigateToHome() {
        let homeVC = HomeViewController()
        homeVC.modalPresentationStyle = .fullScreen
        homeVC.modalTransitionStyle = .crossDissolve
        present(homeVC, animated: true)
    }
    
    private func navigateToLogin() {
        let loginVC = LoginViewController()
        loginVC.modalPresentationStyle = .fullScreen
        loginVC.modalTransitionStyle = .crossDissolve
        present(loginVC, animated: true)
    }
}